import jwt
import secrets
from datetime import datetime, timedelta
from typing import Dict, Optional

# Generate a strong secret key (in production, load from secure environment variable)
SECRET_KEY = secrets.token_urlsafe(64)
ALGORITHM = "HS256"
TOKEN_EXPIRATION_HOURS = 24
REFRESH_TOKEN_EXPIRATION_DAYS = 7

def generate_jwt_token(user_id: str, role: str, token_type: str = "access") -> str:
    """
    Generate a secure JWT token for user authentication.
    
    Args:
        user_id: Unique identifier for the user
        role: User's role (e.g., 'admin', 'user')
        token_type: Type of token ('access' or 'refresh')
    
    Returns:
        Encoded JWT token string
    """
    now = datetime.utcnow()
    
    if token_type == "refresh":
        expiration = now + timedelta(days=REFRESH_TOKEN_EXPIRATION_DAYS)
    else:
        expiration = now + timedelta(hours=TOKEN_EXPIRATION_HOURS)
    
    payload = {
        'user_id': user_id,
        'role': role,
        'token_type': token_type,
        'iat': now,
        'exp': expiration,
        'nbf': now,
        'jti': secrets.token_urlsafe(16)
    }
    
    token = jwt.encode(
        payload,
        SECRET_KEY,
        algorithm=ALGORITHM
    )
    
    return token

def verify_jwt_token(token: str) -> Optional[Dict]:
    """
    Verify and decode a JWT token with strict validation.
    
    Args:
        token: JWT token string to verify
    
    Returns:
        Decoded payload if valid, None otherwise
    """
    try:
        payload = jwt.decode(
            token,
            SECRET_KEY,
            algorithms=[ALGORITHM],
            options={
                'verify_signature': True,
                'verify_exp': True,
                'verify_nbf': True,
                'verify_iat': True,
                'require': ['exp', 'iat', 'nbf', 'user_id', 'role', 'token_type', 'jti']
            }
        )
        return payload
    except jwt.ExpiredSignatureError:
        print("Token has expired")
        return None
    except jwt.InvalidTokenError as e:
        print(f"Invalid token: {e}")
        return None
    except Exception as e:
        print(f"Token verification failed: {e}")
        return None

def refresh_access_token(refresh_token: str) -> Optional[str]:
    """
    Generate a new access token using a valid refresh token.
    
    Args:
        refresh_token: Valid refresh token
    
    Returns:
        New access token if refresh token is valid, None otherwise
    """
    payload = verify_jwt_token(refresh_token)
    
    if not payload:
        return None
    
    if payload.get('token_type') != 'refresh':
        print("Invalid token type for refresh")
        return None
    
    new_access_token = generate_jwt_token(
        user_id=payload['user_id'],
        role=payload['role'],
        token_type='access'
    )
    
    return new_access_token

def user_login(user_id: str, role: str) -> Dict[str, str]:
    """
    Simulate user login and generate both access and refresh tokens.
    
    Args:
        user_id: User's unique identifier
        role: User's role
    
    Returns:
        Dictionary containing access_token and refresh_token
    """
    access_token = generate_jwt_token(user_id, role, token_type='access')
    refresh_token = generate_jwt_token(user_id, role, token_type='refresh')
    
    return {
        'access_token': access_token,
        'refresh_token': refresh_token
    }

def check_user_permission(token: str, required_role: str) -> bool:
    """
    Check if user has required role based on JWT token.
    
    Args:
        token: JWT access token
        required_role: Required role for access
    
    Returns:
        True if user has required role, False otherwise
    """
    payload = verify_jwt_token(token)
    
    if not payload:
        return False
    
    if payload.get('token_type') != 'access':
        print("Invalid token type for authentication")
        return False
    
    user_role = payload.get('role')
    
    role_hierarchy = {
        'admin': 3,
        'moderator': 2,
        'user': 1
    }
    
    user_level = role_hierarchy.get(user_role, 0)
    required_level = role_hierarchy.get(required_role, 0)
    
    return user_level >= required_level


